UPDATE user_coupons
SET used_yn = 'Y',
    used_at = CURRENT_TIMESTAMP
WHERE user_coupon_id = #{user_coupon_id}
AND user_id = #{user_id}
AND used_yn = 'N'

mapper.select:
SELECT COUNT(*)
FROM point_history
WHERE user_id = #{user_id}
AND order_item_id = #{order_item_id}
AND type = 'EARN'

SELECT COALESCE(point_balance, 0)
FROM user_points
WHERE user_id = #{user_id}

mapper.update:
UPDATE user_points
SET point_balance = point_balance - #{point_amount},
    updated_at = CURRENT_TIMESTAMP
WHERE user_id = #{user_id}
AND point_balance >= #{point_amount}

UPDATE user_coupons
SET used_yn = 'N',
    used_at = NULL
WHERE user_coupon_id = #{user_coupon_id}
AND user_id = #{user_id}
AND used_yn = 'Y'

