SELECT COALESCE(SUM(point_amount), 0)
FROM point_history
WHERE user_id = #{user_id}
AND order_id = #{order_id}
AND type = 'USE'

SELECT COUNT(*)
FROM point_history
WHERE user_id = #{user_id}
AND order_id = #{order_id}
AND type = 'REFUND'

SELECT COUNT(DISTINCT o.order_id) FROM orders o JOIN users u ON u.user_id = o.user_id LEFT JOIN payments pay ON pay.order_id = o.order_id LEFT JOIN order_items oi ON oi.order_id = o.order_id LEFT JOIN products p ON p.product_id = oi.product_id WHERE 1 = 1
AND o.status = UPPER(#{status})
AND o.user_id = #{userId}
AND ( CAST(o.order_id AS CHAR) LIKE CONCAT('%', #{keyword}, '%') OR u.name LIKE CONCAT('%', #{keyword}, '%') OR u.login_id LIKE CONCAT('%', #{keyword}, '%') OR u.email LIKE CONCAT('%', #{keyword}, '%') OR p.name LIKE CONCAT('%', #{keyword}, '%') OR pay.transaction_id LIKE CONCAT('%', #{keyword}, '%') )
AND DATE(o.created_at) >= #{startDate}
AND DATE(o.created_at) <= #{endDate}

SELECT o.order_id, o.user_id, u.name AS user_name, u.login_id, u.email, o.total_amount, o.status, o.created_at, o.updated_at, pay.payment_method, pay.status AS payment_status, pay.amount AS payment_amount, COUNT(DISTINCT oi.order_item_id) AS item_count, MIN(p.name) AS first_product_name, CASE WHEN COUNT(DISTINCT oi.order_item_id) > 1 THEN CONCAT(MIN(p.name), ' 외 ', COUNT(DISTINCT oi.order_item_id) - 1, '건') ELSE MIN(p.name) END AS order_name FROM orders o JOIN users u ON u.user_id = o.user_id LEFT JOIN payments pay ON pay.order_id = o.order_id LEFT JOIN order_items oi ON oi.order_id = o.order_id LEFT JOIN products p ON p.product_id = oi.product_id WHERE 1 = 1
AND o.status = UPPER(#{status})
AND o.user_id = #{userId}
AND ( CAST(o.order_id AS CHAR) LIKE CONCAT('%', #{keyword}, '%') OR u.name LIKE CONCAT('%', #{keyword}, '%') OR u.login_id LIKE CONCAT('%', #{keyword}, '%') OR u.email LIKE CONCAT('%', #{keyword}, '%') OR p.name LIKE CONCAT('%', #{keyword}, '%') OR pay.transaction_id LIKE CONCAT('%', #{keyword}, '%') )
AND DATE(o.created_at) >= #{startDate}
AND DATE(o.created_at) <= #{endDate}
GROUP BY o.order_id, o.user_id, u.name, u.login_id, u.email, o.total_amount, o.status, o.created_at, o.updated_at, pay.payment_method, pay.status, pay.amount
ORDER BY o.order_id ASC
ORDER BY o.total_amount DESC, o.order_id DESC
ORDER BY o.order_id DESC
LIMIT #{size} OFFSET #{offset}
